const CN = {
  "workflowName": "田子坊每日客流报告",
  "titlePrefix": "📊 田子坊昨日统计",
  "scope": "- 统计口径：仅使用官方实时接口返回的 measured 在园人数样本",
  "noSamples": "- 暂无有效在园人数样本。",
  "sampleLineA": "- 实际样本数：",
  "sampleLineB": " 条（实测 ",
  "sampleLineC": "，API冻结 0，估算 0）",
  "firstUpdateA": "- 官方首次更新：",
  "firstUpdateB": "（采集于 ",
  "people": " 人",
  "closeParen": "）",
  "maxA": "- 最高在园：",
  "maxB": " 人（",
  "avgA": "- 平均在园：",
  "minA": "- 最低在园：",
  "windowA": "- 官方实时数据窗口：首次更新至 ",
  "peakHoursA": "- 高峰小时：",
  "pointApprox": "点≈",
  "sep": "；",
  "lastA": "- 最后采样：",
  "comfortA": "，舒适度：",
  "contextA": "- 日期背景："
};
const row = ($json.rows || [])[0] || {};
const date = row.date;
const samples = Array.isArray(row.samples) ? row.samples : [];

function sqlText(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}` + "'";
}
function sqlNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? String(Math.round(number)) : 'NULL';
}
function sqlFloat(value) {
  const number = Number(value);
  return Number.isFinite(number) ? String(number) : 'NULL';
}
function shanghaiTime(value) {
  if (!value) return '';
  return new Intl.DateTimeFormat('zh-CN', { timeZone: 'Asia/Shanghai', hour: '2-digit', minute: '2-digit', hour12: false }).format(new Date(value));
}
function shanghaiHour(value) {
  if (!value) return null;
  return Number(new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Shanghai', hour: '2-digit', hour12: false }).format(new Date(value)));
}
function parseRaw(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try { return JSON.parse(raw); } catch { return {}; }
}
function avg(values) {
  if (!values.length) return null;
  return Math.round(values.reduce((sum, value) => sum + value, 0) / values.length);
}
function weekdayFromDate(dateText) {
  const dateObj = new Date(`${dateText}T12:00:00+08:00`);
  const weekday = dateObj.getDay();
  return weekday === 0 ? 6 : weekday - 1;
}

const normalizedSamples = samples.map((sample) => ({
  value: Number(sample.value),
  ts: sample.ts,
  confidence: sample.confidence || 'measured',
  raw: parseRaw(sample.raw_json),
})).filter((sample) => Number.isFinite(sample.value));

const reportTs = `${date}T02:00:00+08:00`;
const wd = Number(row.holiday_weekday ?? weekdayFromDate(date));
const holidayRaw = parseRaw(row.holiday_raw);
const holidayName = holidayRaw?.holiday_name || '';
const isHoliday = Number(row.is_holiday || 0);

if (!normalizedSamples.length) {
  const reportText = [`${CN.titlePrefix}（${date}）`, CN.scope, CN.noSamples].join('\n');
  const raw = { date, sample_count: 0, generated_by: 'n8n_daily_report', generated_at: new Date().toISOString() };
  const sql = `INSERT INTO crowd_data (ts, source, metric, value, text_value, unit, confidence, raw_json, created_at)
VALUES (${sqlText(reportTs)}, 'daily_report', 'text', NULL, ${sqlText(reportText)}, '', 'generated', ${sqlText(JSON.stringify(raw))}, NOW())
ON CONFLICT (ts, source, metric) DO UPDATE SET text_value = EXCLUDED.text_value, confidence = EXCLUDED.confidence, raw_json = EXCLUDED.raw_json, created_at = NOW()`;
  return [{ json: { label: 'daily_report.text', sql, reportText, date, sampleCount: 0 } }];
}

const values = normalizedSamples.map((sample) => sample.value);
const max = Math.max(...values);
const min = Math.min(...values);
const average = avg(values);
const sampleValueSum = Math.round(values.reduce((sum, value) => sum + value, 0));
const peak = normalizedSamples.reduce((best, current) => (current.value > best.value ? current : best), normalizedSamples[0]);
const peakHour = shanghaiHour(peak.ts);
const hourGroups = new Map();
for (const sample of normalizedSamples) {
  const hour = shanghaiHour(sample.ts);
  if (hour === null) continue;
  if (!hourGroups.has(hour)) hourGroups.set(hour, []);
  hourGroups.get(hour).push(sample.value);
}
const highHours = [...hourGroups.entries()].map(([hour, hourValues]) => ({ hour, avg: avg(hourValues) })).filter((item) => item.avg !== null).sort((a, b) => b.avg - a.avg).slice(0, 3).map((item) => `${item.hour}${CN.pointApprox}${item.avg}${CN.people.trim()}`).join(CN.sep);
const officialUpdates = normalizedSamples.filter((sample) => sample.raw?.source === 'sh_a_scenic_realtime' && sample.raw?.time).map((sample) => ({ collectTs: sample.ts, officialTime: sample.raw.time, value: sample.value })).filter((item, index, arr) => arr.findIndex((x) => x.officialTime === item.officialTime) === index).sort((a, b) => String(a.officialTime).localeCompare(String(b.officialTime)));
const firstOfficialUpdate = officialUpdates[0];
const lastSample = normalizedSamples.at(-1);
const lines = [`${CN.titlePrefix}（${date}）`, CN.scope, `${CN.sampleLineA}${normalizedSamples.length}${CN.sampleLineB}${normalizedSamples.length}${CN.sampleLineC}`];
if (firstOfficialUpdate) lines.push(`${CN.firstUpdateA}${String(firstOfficialUpdate.officialTime).slice(11, 16)}${CN.firstUpdateB}${shanghaiTime(firstOfficialUpdate.collectTs)}，${Math.round(firstOfficialUpdate.value)}${CN.people}${CN.closeParen}`);
lines.push(`${CN.maxA}${Math.round(max)}${CN.maxB}${shanghaiTime(peak.ts)}${CN.closeParen}`, `${CN.avgA}${average}${CN.people}`, `${CN.minA}${Math.round(min)}${CN.people}`);
if (officialUpdates.length) lines.push(`${CN.windowA}${String(officialUpdates.at(-1).officialTime).slice(11, 16)}`);
if (highHours) lines.push(`${CN.peakHoursA}${highHours}`);
if (lastSample) {
  const comfort = lastSample.raw?.comfort ? `${CN.comfortA}${lastSample.raw.comfort}` : '';
  lines.push(`${CN.lastA}${shanghaiTime(lastSample.ts)}，${Math.round(lastSample.value)}${CN.people}${comfort}`);
}
if (holidayName) lines.push(`${CN.contextA}${holidayName}`);
const reportText = lines.join('\n');
const raw = { date, generated_by: 'n8n_daily_report', generated_at: new Date().toISOString(), sample_count: normalizedSamples.length, max_crowd: Math.round(max), avg_crowd: average, min_crowd: Math.round(min), peak_hour: peakHour, is_holiday: isHoliday, holiday_name: holidayName || null };
const notes = ['auto_summary_n8n', `samples=${normalizedSamples.length}`, `in_park_sample_sum=${sampleValueSum}`, 'total_visitors=null_without_cumulative_source', `confidence={"measured":${normalizedSamples.length}}`, holidayName ? `holiday=${holidayName}` : null].filter(Boolean).join('; ');
const summarySql = `INSERT INTO daily_summary (date, weekday, max_crowd, avg_crowd, peak_hour, total_visitors, notes, weather_desc, temperature_high, temperature_low, is_holiday, holiday_name)
VALUES (${sqlText(date)}, ${sqlNumber(wd)}, ${sqlNumber(max)}, ${sqlFloat(average)}, ${sqlNumber(peakHour)}, NULL, ${sqlText(notes)}, NULL, NULL, NULL, ${sqlNumber(isHoliday)}, ${sqlText(holidayName || null)})
ON CONFLICT (date) DO UPDATE SET weekday = EXCLUDED.weekday, max_crowd = EXCLUDED.max_crowd, avg_crowd = EXCLUDED.avg_crowd, peak_hour = EXCLUDED.peak_hour, total_visitors = EXCLUDED.total_visitors, notes = EXCLUDED.notes, weather_desc = EXCLUDED.weather_desc, temperature_high = EXCLUDED.temperature_high, temperature_low = EXCLUDED.temperature_low, is_holiday = EXCLUDED.is_holiday, holiday_name = EXCLUDED.holiday_name`;
const reportSql = `INSERT INTO crowd_data (ts, source, metric, value, text_value, unit, confidence, raw_json, created_at)
VALUES (${sqlText(reportTs)}, 'daily_report', 'text', NULL, ${sqlText(reportText)}, '', 'generated', ${sqlText(JSON.stringify(raw))}, NOW())
ON CONFLICT (ts, source, metric) DO UPDATE SET text_value = EXCLUDED.text_value, confidence = EXCLUDED.confidence, raw_json = EXCLUDED.raw_json, created_at = NOW()`;
return [{ json: { label: 'daily_summary', sql: summarySql, reportText, date, sampleCount: normalizedSamples.length } }, { json: { label: 'daily_report.text', sql: reportSql, reportText, date, sampleCount: normalizedSamples.length } }];
